/**
 * temp_redeploy_myb.ts - SECURED VERSION
 * 
 * Emergency deployment for My Business Token (MYB)
 * 
 * SECURITY:
 * - Authentication required
 * - Admin/super_admin only
 * - OR whitelisted emails
 * - OR emergency secret token
 * 
 * REMOVE OR DISABLE after emergency is resolved
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';
import { ethers } from 'npm:ethers@6.13.0';

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { status: 204 });
  }

  try {
    const base44 = createClientFromRequest(req);

    // ============================================================
    // SECURITY CHECK - CRITICAL
    // ============================================================
    const user = await base44.auth.me();
    if (!user) {
      return Response.json({ error: 'Unauthorized - Authentication required' }, { status: 401 });
    }

    const allowedEmails = [
      'arbel.amir.s@gmail.com',
      'xiaxiyu4@gmail.com'
    ];

    const emergencySecret = Deno.env.get('EMERGENCY_DEPLOY_SECRET');
    const body = await req.json().catch(() => ({}));
    const providedSecret = body?.secret || req.headers.get('x-emergency-secret');

    const isAllowedUser =
      user.role === 'admin' ||
      user.role === 'super_admin' ||
      allowedEmails.includes((user.email || '').toLowerCase());

    const hasValidSecret = emergencySecret && providedSecret === emergencySecret;

    if (!isAllowedUser && !hasValidSecret) {
      console.warn('⚠️ Unauthorized deployment attempt:', {
        user_email: user.email,
        user_role: user.role,
        timestamp: new Date().toISOString()
      });
      return Response.json({ 
        error: 'Forbidden - Admin access required',
        user_role: user.role
      }, { status: 403 });
    }

    console.log('✅ Authorized deployment:', {
      user_email: user.email,
      user_role: user.role,
      method: hasValidSecret ? 'emergency_secret' : 'role_or_email'
    });

    // ============================================================
    // DEPLOYMENT LOGIC
    // ============================================================

    console.log('🚀 Starting MYB deployment...');

    const companyId = '699c3f84f1834f4fe65cd16c';
    const network = 'fuji';

    const ABI = [
      'constructor(string memory name_, string memory symbol_, uint256 initialSupply_)',
      'function name() view returns (string)',
      'function symbol() view returns (string)',
      'function totalSupply() view returns (uint256)',
      'function balanceOf(address) view returns (uint256)',
      'function mint(address to, uint256 amount)',
      'function burn(address from, uint256 amount)',
      'function owner() view returns (address)'
    ];

    const BYTECODE = '';

    const rpcUrl = 'https://api.avax-test.network/ext/bc/C/rpc';
    const privateKey = Deno.env.get('GAS_WALLET_PRIVATE_KEY') || Deno.env.get('OWNER_PRIVATE_KEY');
    
    if (!privateKey) {
      return Response.json({ error: 'Private key not found in secrets' }, { status: 500 });
    }

    const provider = new ethers.JsonRpcProvider(rpcUrl);
    const deployer = new ethers.Wallet(privateKey, provider);
    const deployerAddress = deployer.address;

    console.log('🔑 Deployer:', deployerAddress);

    const balance = await provider.getBalance(deployerAddress);
    const balanceInAvax = ethers.formatEther(balance);
    
    console.log('💰 Balance:', balanceInAvax, 'AVAX');

    if (parseFloat(balanceInAvax) < 0.1) {
      return Response.json({ 
        error: 'Insufficient AVAX',
        balance: balanceInAvax
      }, { status: 500 });
    }

    const tokenName = 'My Business Token';
    const tokenSymbol = 'MYB';
    const initialSupply = 1000000;

    console.log('📝 Deploy params:', { tokenName, tokenSymbol, initialSupply });

    const factory = new ethers.ContractFactory(ABI, BYTECODE, deployer);

    console.log('🚀 Deploying SimpleToken (MYB)...');

    const contract = await factory.deploy(
      tokenName,
      tokenSymbol,
      initialSupply
    );

    await contract.waitForDeployment();
    const newContractAddress = await contract.getAddress();

    console.log('✅ Contract deployed:', newContractAddress);

    const deployedName = await contract.name();
    const deployedSymbol = await contract.symbol();
    const deployedSupply = await contract.totalSupply();
    const ownerAddress = await contract.owner();

    console.log('✅ Verification:', {
      name: deployedName,
      symbol: deployedSymbol,
      supply: ethers.formatUnits(deployedSupply, 18),
      owner: ownerAddress
    });

    console.log('💾 Updating database...');

    const companies = await base44.asServiceRole.entities.Company.filter({ id: companyId });
    const company = companies[0];
    
    if (!company) {
      return Response.json({ error: 'Company not found' }, { status: 404 });
    }

    const tokens = await base44.asServiceRole.entities.CompanyToken.filter({ company_id: companyId });
    const existingToken = tokens.find(t => t.is_active !== false);

    if (existingToken) {
      await base44.asServiceRole.entities.CompanyToken.update(existingToken.id, {
        is_active: false,
        updated_date: new Date().toISOString()
      });
      console.log('✅ Old token marked inactive:', existingToken.contract_address);
    }

    const newToken = await base44.asServiceRole.entities.CompanyToken.create({
      company_id: companyId,
      token_name: tokenName,
      token_symbol: tokenSymbol,
      contract_address: newContractAddress,
      chain: 'avalanche_fuji',
      treasury_wallet: deployerAddress,
      is_active: true,
      initial_supply: initialSupply.toString(),
      current_supply: initialSupply.toString(),
      created_date: new Date().toISOString()
    });

    console.log('✅ Database updated');

    await base44.asServiceRole.entities.Company.update(companyId, {
      blockchain_wallet_address: deployerAddress,
      onchain_network: 'fuji',
      updated_date: new Date().toISOString()
    });

    return Response.json({
      success: true,
      message: 'MYB deployed successfully (SECURED)',
      contract_address: newContractAddress,
      deployer: deployerAddress,
      deployed_by: user.email,
      token_id: newToken.id,
      snowtrace_url: `https://testnet.snowtrace.io/address/${newContractAddress}`,
      verification: {
        name: deployedName,
        symbol: deployedSymbol,
        supply: ethers.formatUnits(deployedSupply, 18),
        owner: ownerAddress
      }
    });

  } catch (error) {
    console.error('❌ Deployment error:', error.message, error.stack);
    return Response.json({ 
      error: error.message,
      stack: error.stack
    }, { status: 500 });
  }
});